import assert from "node:assert/strict";
import test from "node:test";
import {
  apiErrorPayloadSchema,
  apiPaginationMetaSchema,
  auditLogRecordSchema,
  importListItemSchema,
  normalizeApiPaginationMeta,
} from "@shared/api-contracts";
import { ERROR_CODES } from "@shared/error-codes";
import {
  getImportData,
  getImports,
  deleteImport,
  renameImport,
} from "@/lib/api/imports";
import { getAuditLogs } from "@/lib/api/audit";
import { advancedSearchData, getSearchColumns, searchData } from "@/lib/api/search";
import {
  getSettings,
  getTabVisibility,
  updateSetting,
} from "@/lib/api/settings";

function withMockFetch(mock: typeof fetch): () => void {
  const originalFetch = globalThis.fetch;
  globalThis.fetch = mock;
  return () => {
    globalThis.fetch = originalFetch;
  };
}

function jsonResponse(body: unknown): Response {
  return new Response(JSON.stringify(body), {
    status: 200,
    headers: {
      "Content-Type": "application/json",
    },
  });
}

test("shared API contracts accept nullish actor fields without widening required fields", () => {
  const importRecord = importListItemSchema.safeParse({
    id: "import-123",
    name: "March Import",
    filename: "march.csv",
    createdAt: "2026-03-26T00:00:00.000Z",
    isDeleted: false,
    createdBy: null,
    rowCount: 12,
  });
  assert.equal(importRecord.success, true);

  const auditRecord = auditLogRecordSchema.safeParse({
    id: "audit-1",
    action: "LOGIN",
    performedBy: "admin.user",
    timestamp: "2026-03-26T00:00:00.000Z",
  });
  assert.equal(auditRecord.success, true);

  const malformedAuditRecord = auditLogRecordSchema.safeParse({
    id: "audit-1",
    action: "LOGIN",
    performedBy: "admin.user",
  });
  assert.equal(malformedAuditRecord.success, false);
});

test("shared API error payload contract accepts shared and domain-specific uppercase codes only", () => {
  const sharedCodePayload = apiErrorPayloadSchema.safeParse({
    ok: false,
    message: "Forbidden",
    code: ERROR_CODES.PERMISSION_DENIED,
  });
  assert.equal(sharedCodePayload.success, true);

  const domainCodePayload = apiErrorPayloadSchema.safeParse({
    ok: false,
    message: "Conflict",
    error: {
      code: "USERNAME_TAKEN",
      message: "Username already exists.",
    },
  });
  assert.equal(domainCodePayload.success, true);

  const malformedCodePayload = apiErrorPayloadSchema.safeParse({
    ok: false,
    message: "Bad request",
    code: "permission_denied",
  });
  assert.equal(malformedCodePayload.success, false);
});

test("shared pagination metadata can be normalized without changing wire contracts", () => {
  assert.equal(apiPaginationMetaSchema.safeParse({
    mode: "offset",
    page: 2,
    pageSize: 25,
    limit: 25,
    offset: 25,
    total: 40,
    totalPages: 2,
    hasNextPage: false,
    hasPreviousPage: true,
  }).success, true);

  assert.deepEqual(
    normalizeApiPaginationMeta({
      mode: "cursor",
      limit: 100,
      nextCursor: "cursor-2",
      hasMore: true,
      total: 250,
    }),
    {
      mode: "cursor",
      page: null,
      pageSize: 100,
      limit: 100,
      offset: null,
      total: 250,
      totalPages: null,
      nextCursor: "cursor-2",
      hasNextPage: true,
      hasPreviousPage: false,
      hasMore: true,
    },
  );

  assert.deepEqual(
    normalizeApiPaginationMeta({
      mode: "hybrid",
      page: 3,
      pageSize: 50,
      limit: 50,
      offset: 100,
      total: 151,
      totalPages: 4,
      nextCursor: "cursor-4",
      hasNextPage: false,
      hasPreviousPage: true,
    }),
    {
      mode: "hybrid",
      page: 3,
      pageSize: 50,
      limit: 50,
      offset: 100,
      total: 151,
      totalPages: 4,
      nextCursor: "cursor-4",
      hasNextPage: false,
      hasPreviousPage: true,
      hasMore: true,
    },
  );
});

test("imports API wrappers accept payloads that match the shared contract", async () => {
  const restoreFetch = withMockFetch((async (input) => {
    const url = String(input);

    if (url.startsWith("/api/imports/import-123/data")) {
      return jsonResponse({
        rows: [
          {
            id: "row-1",
            importId: "import-123",
            jsonDataJsonb: { name: "Alice" },
          },
        ],
        headers: ["name", "email"],
        total: 1,
        page: 1,
        limit: 50,
        pageSize: 50,
        offset: 0,
        nextCursor: null,
        pagination: {
          mode: "hybrid",
          page: 1,
          pageSize: 50,
          limit: 50,
          offset: 0,
          total: 1,
          totalPages: 1,
          nextCursor: null,
          hasNextPage: false,
          hasPreviousPage: false,
        },
      });
    }

    if (url === "/api/imports") {
      return jsonResponse({
        imports: [
          {
            id: "import-123",
            name: "March Import",
            filename: "march.csv",
            createdAt: "2026-03-26T00:00:00.000Z",
            isDeleted: false,
            createdBy: "admin.user",
            rowCount: 12,
          },
        ],
        pagination: {
          mode: "cursor",
          limit: 100,
          pageSize: 100,
          nextCursor: null,
          hasMore: false,
          total: 1,
        },
      });
    }

    if (url === "/api/imports/import-123/rename") {
      return jsonResponse({
        id: "import-123",
        name: "Renamed Import",
        filename: "march.csv",
        createdAt: "2026-03-26T00:00:00.000Z",
        isDeleted: false,
        createdBy: "admin.user",
      });
    }

    if (url === "/api/imports/import-123") {
      return jsonResponse({
        ok: true,
        success: true,
      });
    }

    throw new Error(`Unexpected URL: ${url}`);
  }) as typeof fetch);

  try {
    const imports = await getImports();
    const importPage = await getImportData("import-123", 1, 50);
    const renamed = await renameImport("import-123", "Renamed Import");
    const deleted = await deleteImport("import-123");

    assert.equal(imports.imports[0]?.rowCount, 12);
    assert.equal(imports.pagination.mode, "cursor");
    assert.equal(importPage.rows[0]?.jsonDataJsonb?.name, "Alice");
    assert.deepEqual(importPage.headers, ["name", "email"]);
    assert.equal(importPage.pagination.mode, "hybrid");
    assert.equal(renamed.name, "Renamed Import");
    assert.equal(deleted.success, true);
  } finally {
    restoreFetch();
  }
});

test("search and audit API wrappers accept payloads that match the shared contract", async () => {
  const restoreFetch = withMockFetch((async (input, init) => {
    const url = String(input);
    const method = String(init?.method || "GET").toUpperCase();

    if (url === "/api/search/global?q=alice&page=2&pageSize=25") {
      return jsonResponse({
        columns: ["name", "Source File"],
        rows: [{ name: "Alice", "Source File": "march.csv" }],
        results: [{ name: "Alice", "Source File": "march.csv" }],
        total: 40,
        page: 2,
        limit: 25,
        pageSize: 25,
        offset: 25,
        pagination: {
          mode: "offset",
          page: 2,
          pageSize: 25,
          limit: 25,
          offset: 25,
          total: 40,
          totalPages: 2,
          hasNextPage: false,
          hasPreviousPage: true,
        },
      });
    }

    if (url === "/api/search/advanced" && method === "POST") {
      return jsonResponse({
        results: [{ name: "Alice", "Source File": "march.csv" }],
        headers: ["name", "Source File"],
        total: 40,
        page: 2,
        limit: 25,
        pageSize: 25,
        offset: 25,
        pagination: {
          mode: "offset",
          page: 2,
          pageSize: 25,
          limit: 25,
          offset: 25,
          total: 40,
          totalPages: 2,
          hasNextPage: false,
          hasPreviousPage: true,
        },
      });
    }

    if (url === "/api/search/columns") {
      return jsonResponse(["name", "phone"]);
    }

    if (url === "/api/audit-logs?page=2&pageSize=25") {
      return jsonResponse({
        logs: [
          {
            id: "audit-1",
            action: "LOGIN",
            performedBy: "admin.user",
            requestId: null,
            targetUser: "alice",
            targetResource: "auth:login",
            details: "Successful login",
            timestamp: "2026-03-26T00:00:00.000Z",
          },
        ],
        pagination: {
          mode: "offset",
          page: 2,
          pageSize: 25,
          limit: 25,
          offset: 25,
          total: 26,
          totalPages: 2,
          hasNextPage: false,
          hasPreviousPage: true,
        },
      });
    }

    throw new Error(`Unexpected URL: ${url}`);
  }) as typeof fetch);

  try {
    const global = await searchData("alice", 2, 25);
    const advanced = await advancedSearchData(
      [{ field: "name", operator: "contains", value: "alice" }],
      "AND",
      2,
      25,
    );
    const columns = await getSearchColumns();
    const audit = await getAuditLogs({ page: 2, pageSize: 25 });

    assert.equal(global.pagination.mode, "offset");
    assert.equal(global.pagination.offset, 25);
    assert.equal(advanced.pagination.totalPages, 2);
    assert.deepEqual(columns, ["name", "phone"]);
    assert.equal(audit.pagination.mode, "offset");
    assert.equal(audit.logs[0]?.action, "LOGIN");
  } finally {
    restoreFetch();
  }
});

test("search and audit API wrappers reject malformed contract payloads", async () => {
  const restoreFetch = withMockFetch((async (input, init) => {
    const url = String(input);
    const method = String(init?.method || "GET").toUpperCase();

    if (url.startsWith("/api/search/global?")) {
      return jsonResponse({ results: [], total: 0 });
    }

    if (url === "/api/search/advanced" && method === "POST") {
      return jsonResponse({ results: [], total: 0 });
    }

    if (url === "/api/search/columns") {
      return jsonResponse([""]);
    }

    if (url.startsWith("/api/audit-logs?")) {
      return jsonResponse({ logs: [] });
    }

    throw new Error(`Unexpected URL: ${url}`);
  }) as typeof fetch);

  try {
    await assert.rejects(() => searchData("alice", 1, 25), /API contract mismatch for \/api\/search\/global/);
    await assert.rejects(
      () => advancedSearchData([{ field: "name", operator: "contains", value: "alice" }], "AND", 1, 25),
      /API contract mismatch for \/api\/search\/advanced/,
    );
    await assert.rejects(() => getSearchColumns(), /API contract mismatch for \/api\/search\/columns/);
    await assert.rejects(() => getAuditLogs({ page: 1, pageSize: 25 }), /API contract mismatch for \/api\/audit-logs/);
  } finally {
    restoreFetch();
  }
});

test("imports API wrappers reject malformed contract payloads", async () => {
  const restoreFetch = withMockFetch((async (input) => {
    const url = String(input);

    if (url === "/api/imports") {
      return jsonResponse({
        ok: true,
      });
    }

    if (url.startsWith("/api/imports/import-123/data")) {
      return jsonResponse({
        rows: [],
        total: 0,
      });
    }

    return jsonResponse({});
  }) as typeof fetch);

  try {
    await assert.rejects(() => getImports(), /API contract mismatch for \/api\/imports/);
    await assert.rejects(
      () => getImportData("import-123", 1, 50),
      /API contract mismatch for \/api\/imports\/import-123\/data/,
    );
  } finally {
    restoreFetch();
  }
});

test("API wrappers reject non-object JSON rows for import and search payloads", async () => {
  const restoreFetch = withMockFetch((async (input, init) => {
    const url = String(input);
    const method = String(init?.method || "GET").toUpperCase();

    if (url.startsWith("/api/imports/import-123/data")) {
      return jsonResponse({
        rows: [
          {
            id: "row-1",
            importId: "import-123",
            jsonDataJsonb: ["unexpected-array"],
          },
        ],
        headers: ["name"],
        total: 1,
        page: 1,
        limit: 50,
        pageSize: 50,
        offset: 0,
        nextCursor: null,
        pagination: {
          mode: "hybrid",
          page: 1,
          pageSize: 50,
          limit: 50,
          offset: 0,
          total: 1,
          totalPages: 1,
          nextCursor: null,
          hasNextPage: false,
          hasPreviousPage: false,
        },
      });
    }

    if (url.startsWith("/api/search/global?")) {
      return jsonResponse({
        columns: ["name"],
        rows: [["unexpected-array"]],
        results: [["unexpected-array"]],
        total: 1,
        page: 1,
        limit: 25,
        pageSize: 25,
        offset: 0,
        pagination: {
          mode: "offset",
          page: 1,
          pageSize: 25,
          limit: 25,
          offset: 0,
          total: 1,
          totalPages: 1,
          hasNextPage: false,
          hasPreviousPage: false,
        },
      });
    }

    if (url === "/api/search/advanced" && method === "POST") {
      return jsonResponse({
        results: [["unexpected-array"]],
        headers: ["name"],
        total: 1,
        page: 1,
        limit: 25,
        pageSize: 25,
        offset: 0,
        pagination: {
          mode: "offset",
          page: 1,
          pageSize: 25,
          limit: 25,
          offset: 0,
          total: 1,
          totalPages: 1,
          hasNextPage: false,
          hasPreviousPage: false,
        },
      });
    }

    throw new Error(`Unexpected URL: ${url}`);
  }) as typeof fetch);

  try {
    await assert.rejects(
      () => getImportData("import-123", 1, 50),
      /API contract mismatch for \/api\/imports\/import-123\/data/,
    );
    await assert.rejects(() => searchData("alice", 1, 25), /API contract mismatch for \/api\/search\/global/);
    await assert.rejects(
      () => advancedSearchData([{ field: "name", operator: "contains", value: "alice" }], "AND", 1, 25),
      /API contract mismatch for \/api\/search\/advanced/,
    );
  } finally {
    restoreFetch();
  }
});

test("settings API wrappers accept payloads that match the shared contract", async () => {
  const restoreFetch = withMockFetch((async (input, init) => {
    const url = String(input);
    const method = String(init?.method || "GET").toUpperCase();

    if (url === "/api/settings" && method === "GET") {
      return jsonResponse({
        categories: [
          {
            id: "general",
            name: "General",
            description: null,
            settings: [
              {
                key: "system_name",
                label: "System Name",
                description: null,
                type: "text",
                value: "SQR",
                defaultValue: "SQR",
                isCritical: false,
                updatedAt: "2026-03-26T00:00:00.000Z",
                permission: {
                  canView: true,
                  canEdit: true,
                },
                options: [],
              },
            ],
          },
        ],
      });
    }

    if (url === "/api/settings" && method === "PATCH") {
      return jsonResponse({
        ok: true,
        success: true,
        status: "updated",
        message: "Updated.",
        setting: {
          key: "system_name",
          label: "System Name",
          description: null,
          type: "text",
          value: "SQR Next",
          defaultValue: "SQR",
          isCritical: false,
          updatedAt: "2026-03-26T00:00:00.000Z",
          permission: {
            canView: true,
            canEdit: true,
          },
          options: [],
        },
      });
    }

    if (url === "/api/settings/tab-visibility") {
      return jsonResponse({
        role: "admin",
        tabs: {
          settings: true,
          home: true,
        },
      });
    }

    throw new Error(`Unexpected URL: ${url}`);
  }) as typeof fetch);

  try {
    const settings = await getSettings();
    const tabVisibility = await getTabVisibility();
    const updated = await updateSetting({ key: "system_name", value: "SQR Next" });

    assert.equal(settings.categories[0]?.settings[0]?.key, "system_name");
    assert.equal(tabVisibility.tabs.settings, true);
    assert.equal(updated.status, "updated");
  } finally {
    restoreFetch();
  }
});

test("updateSetting rejects malformed success payloads", async () => {
  const restoreFetch = withMockFetch((async () =>
    jsonResponse({
      success: true,
      message: "Updated.",
    })) as typeof fetch);

  try {
    await assert.rejects(
      () => updateSetting({ key: "system_name", value: "SQR Next" }),
      /API contract mismatch for \/api\/settings/,
    );
  } finally {
    restoreFetch();
  }
});

import { z } from "zod";
import { jsonObjectSchema, jsonValueSchema } from "./json-schema";
import { sharedErrorCodeSchema } from "./error-codes";

const nonEmptyStringSchema = z.string().trim().min(1);
const nullableStringSchema = z.string().nullable();
const nullishStringSchema = z.string().nullish();
const nonNegativeIntSchema = z.number().int().nonnegative();
const positiveIntSchema = z.number().int().positive();
const paginationLimitSchema = z.number().int().positive().max(1000);
export const apiErrorCodeSchema = z.union([
  sharedErrorCodeSchema,
  z.string().trim().regex(/^[A-Z][A-Z0-9_]*$/),
]);

export const offsetPaginationMetaSchema = z.object({
  mode: z.literal("offset"),
  page: positiveIntSchema,
  pageSize: paginationLimitSchema,
  limit: paginationLimitSchema,
  offset: nonNegativeIntSchema,
  total: nonNegativeIntSchema,
  totalPages: positiveIntSchema,
  hasNextPage: z.boolean(),
  hasPreviousPage: z.boolean(),
});

export const cursorPaginationMetaSchema = z.object({
  mode: z.literal("cursor"),
  limit: paginationLimitSchema,
  pageSize: paginationLimitSchema.optional(),
  nextCursor: nullableStringSchema,
  hasMore: z.boolean(),
  total: nonNegativeIntSchema,
});

export const hybridPaginationMetaSchema = z.object({
  mode: z.literal("hybrid"),
  page: positiveIntSchema,
  pageSize: paginationLimitSchema,
  limit: paginationLimitSchema,
  offset: nonNegativeIntSchema,
  total: nonNegativeIntSchema,
  totalPages: positiveIntSchema,
  nextCursor: nullableStringSchema,
  hasNextPage: z.boolean(),
  hasPreviousPage: z.boolean(),
});

export const apiPaginationMetaSchema = z.discriminatedUnion("mode", [
  offsetPaginationMetaSchema,
  cursorPaginationMetaSchema,
  hybridPaginationMetaSchema,
]);

export const importRecordSchema = z.object({
  id: nonEmptyStringSchema,
  name: nonEmptyStringSchema,
  filename: nonEmptyStringSchema,
  createdAt: nonEmptyStringSchema,
  isDeleted: z.boolean(),
  createdBy: nullishStringSchema,
});

export const importListItemSchema = importRecordSchema.extend({
  rowCount: nonNegativeIntSchema,
});

export const importsListResponseSchema = z.object({
  imports: z.array(importListItemSchema),
  pagination: cursorPaginationMetaSchema,
});

export const importDataRowSchema = z.object({
  id: nonEmptyStringSchema,
  importId: nonEmptyStringSchema,
  jsonDataJsonb: jsonObjectSchema,
});

export const importDataPageResponseSchema = z.object({
  rows: z.array(importDataRowSchema),
  headers: z.array(nonEmptyStringSchema),
  total: nonNegativeIntSchema,
  page: positiveIntSchema,
  limit: paginationLimitSchema,
  pageSize: paginationLimitSchema.optional(),
  offset: nonNegativeIntSchema,
  nextCursor: nullableStringSchema,
  pagination: hybridPaginationMetaSchema,
});

const searchResultRowSchema = jsonObjectSchema;

export const searchGlobalResponseSchema = z.object({
  columns: z.array(nonEmptyStringSchema),
  rows: z.array(searchResultRowSchema),
  results: z.array(searchResultRowSchema),
  total: nonNegativeIntSchema,
  totalIsApproximate: z.boolean().optional(),
  page: positiveIntSchema,
  limit: paginationLimitSchema,
  pageSize: paginationLimitSchema,
  offset: nonNegativeIntSchema,
  pagination: offsetPaginationMetaSchema,
});

export const advancedSearchResponseSchema = z.object({
  results: z.array(searchResultRowSchema),
  headers: z.array(nonEmptyStringSchema),
  total: nonNegativeIntSchema,
  page: positiveIntSchema,
  limit: paginationLimitSchema,
  pageSize: paginationLimitSchema,
  offset: nonNegativeIntSchema,
  pagination: offsetPaginationMetaSchema,
});

export const auditLogRecordSchema = z.object({
  id: nonEmptyStringSchema,
  action: nonEmptyStringSchema,
  performedBy: nonEmptyStringSchema,
  requestId: nullishStringSchema,
  targetUser: nullishStringSchema,
  targetResource: nullishStringSchema,
  details: nullishStringSchema,
  timestamp: nonEmptyStringSchema,
});

export const auditLogsResponseSchema = z.object({
  logs: z.array(auditLogRecordSchema),
  pagination: offsetPaginationMetaSchema,
});

export const apiErrorDetailsSchema = z.object({
  code: apiErrorCodeSchema.optional(),
  message: z.string(),
  details: jsonValueSchema.optional(),
  requestId: z.string().optional(),
}).passthrough();

export const apiErrorPayloadSchema = z.object({
  ok: z.literal(false).optional(),
  message: z.string(),
  requestId: z.string().optional(),
  code: apiErrorCodeSchema.optional(),
  error: apiErrorDetailsSchema.optional(),
}).passthrough();

export const deleteImportResponseSchema = z.object({
  ok: z.literal(true).optional(),
  success: z.boolean(),
});

export const settingOptionSchema = z.object({
  value: z.string(),
  label: z.string(),
});

export const settingPermissionSchema = z.object({
  canView: z.boolean(),
  canEdit: z.boolean(),
});

export const settingItemSchema = z.object({
  key: nonEmptyStringSchema,
  label: nonEmptyStringSchema,
  description: z.string().nullable(),
  type: z.enum(["text", "number", "boolean", "select", "timestamp"]),
  value: z.string(),
  defaultValue: z.string().nullable(),
  isCritical: z.boolean(),
  updatedAt: z.string().nullable(),
  permission: settingPermissionSchema,
  options: z.array(settingOptionSchema),
});

export const settingCategorySchema = z.object({
  id: nonEmptyStringSchema,
  name: nonEmptyStringSchema,
  description: z.string().nullable(),
  settings: z.array(settingItemSchema),
});

export const settingsResponseSchema = z.object({
  categories: z.array(settingCategorySchema),
});

export const settingsUpdateResponseSchema = z.object({
  ok: z.literal(true).optional(),
  success: z.boolean(),
  status: z.enum(["updated", "unchanged"]),
  message: z.string(),
  setting: settingItemSchema.nullable(),
});

export const tabVisibilityResponseSchema = z.object({
  role: nonEmptyStringSchema,
  tabs: z.record(z.boolean()),
});

export type ImportsListResponse = z.infer<typeof importsListResponseSchema>;
export type ImportDataPageResponse = z.infer<typeof importDataPageResponseSchema>;
export type SearchGlobalResponse = z.infer<typeof searchGlobalResponseSchema>;
export type AdvancedSearchResponse = z.infer<typeof advancedSearchResponseSchema>;
export type AuditLogsResponse = z.infer<typeof auditLogsResponseSchema>;
export type ApiErrorPayload = z.infer<typeof apiErrorPayloadSchema>;
export type SettingsResponse = z.infer<typeof settingsResponseSchema>;
export type SettingsUpdateResponse = z.infer<typeof settingsUpdateResponseSchema>;
export type TabVisibilityResponse = z.infer<typeof tabVisibilityResponseSchema>;
export type ApiPaginationMeta = z.infer<typeof apiPaginationMetaSchema>;
export type NormalizedApiPaginationMeta = {
  mode: ApiPaginationMeta["mode"];
  page: number | null;
  pageSize: number;
  limit: number;
  offset: number | null;
  total: number;
  totalPages: number | null;
  nextCursor: string | null;
  hasNextPage: boolean;
  hasPreviousPage: boolean;
  hasMore: boolean;
};

export function normalizeApiPaginationMeta(
  pagination: ApiPaginationMeta,
): NormalizedApiPaginationMeta {
  if (pagination.mode === "cursor") {
    return {
      mode: pagination.mode,
      page: null,
      pageSize: pagination.pageSize ?? pagination.limit,
      limit: pagination.limit,
      offset: null,
      total: pagination.total,
      totalPages: null,
      nextCursor: pagination.nextCursor,
      hasNextPage: pagination.hasMore,
      hasPreviousPage: false,
      hasMore: pagination.hasMore,
    };
  }

  const hasMore = pagination.mode === "hybrid"
    ? pagination.hasNextPage || pagination.nextCursor !== null
    : pagination.hasNextPage;

  return {
    mode: pagination.mode,
    page: pagination.page,
    pageSize: pagination.pageSize,
    limit: pagination.limit,
    offset: pagination.offset,
    total: pagination.total,
    totalPages: pagination.totalPages,
    nextCursor: pagination.mode === "hybrid" ? pagination.nextCursor : null,
    hasNextPage: pagination.hasNextPage,
    hasPreviousPage: pagination.hasPreviousPage,
    hasMore,
  };
}

import { z } from "zod";

export type JsonPrimitive = string | number | boolean | null;
export type JsonValue = JsonPrimitive | JsonObject | JsonValue[];
export type JsonObject = { [key: string]: JsonValue };

const jsonPrimitiveSchema = z.union([
  z.string(),
  z.number().finite(),
  z.boolean(),
  z.null(),
]);

export const jsonValueSchema: z.ZodType<JsonValue> = z.lazy(() =>
  z.union([
    jsonPrimitiveSchema,
    z.array(jsonValueSchema),
    z.record(jsonValueSchema),
  ]),
);

export const jsonObjectSchema: z.ZodType<JsonObject> = z.lazy(() =>
  z.record(jsonValueSchema),
);

import { apiRequest } from "../api-client";
import { parseApiJson } from "./contract";
import {
  deleteImportResponseSchema,
  importDataPageResponseSchema,
  importRecordSchema,
  importsListResponseSchema,
} from "@shared/api-contracts";

const IMPORT_UPLOAD_TIMEOUT_MS = 2 * 60_000;

type ImportRequestOptions = {
  cursor?: string | undefined;
  limit?: number | undefined;
  pageSize?: number | undefined;
  search?: string | undefined;
  createdOn?: string | undefined;
  signal?: AbortSignal | undefined;
};

export type ImportDataColumnFilter = {
  column: string;
  operator: "contains" | "equals" | "startsWith" | "endsWith" | "notEquals";
  value: string;
};

type ImportDataRequestOptions = ImportRequestOptions & {
  columnFilters?: ImportDataColumnFilter[] | undefined;
};

export async function getImports(options?: ImportRequestOptions) {
  const params = new URLSearchParams();
  if (options?.cursor) params.set("cursor", options.cursor);
  const pageSize = options?.pageSize ?? options?.limit;
  if (typeof pageSize === "number" && Number.isFinite(pageSize)) {
    params.set("pageSize", String(pageSize));
  }
  if (options?.search?.trim()) params.set("search", options.search.trim());
  if (options?.createdOn?.trim()) params.set("createdOn", options.createdOn.trim());
  const suffix = params.size > 0 ? `?${params.toString()}` : "";
  const response = await apiRequest("GET", `/api/imports${suffix}`, undefined, options);
  return parseApiJson(response, importsListResponseSchema, "/api/imports");
}

export async function createImport(
  name: string,
  filename: string,
  data: Array<Record<string, unknown>>,
  options?: ImportRequestOptions,
) {
  const response = await apiRequest(
    "POST",
    "/api/imports",
    { name, filename, data },
    options,
  );
  return parseApiJson(response, importRecordSchema, "/api/imports");
}

export async function createImportFromFile(
  name: string,
  file: File,
  options?: ImportRequestOptions,
) {
  const formData = new FormData();
  formData.set("name", name);
  formData.append("file", file, file.name);

  const response = await apiRequest(
    "POST",
    "/api/imports",
    formData,
    {
      ...options,
      timeoutMs: IMPORT_UPLOAD_TIMEOUT_MS,
    },
  );
  return parseApiJson(response, importRecordSchema, "/api/imports");
}

export async function deleteImport(id: string, options?: ImportRequestOptions) {
  const response = await apiRequest("DELETE", `/api/imports/${id}`, undefined, options);
  return parseApiJson(response, deleteImportResponseSchema, `/api/imports/${id}`);
}

export async function renameImport(id: string, name: string, options?: ImportRequestOptions) {
  const response = await apiRequest(
    "PATCH",
    `/api/imports/${id}/rename`,
    { name },
    options,
  );
  return parseApiJson(response, importRecordSchema, `/api/imports/${id}/rename`);
}

export async function getImportData(
  id: string,
  page: number = 1,
  pageSize: number = 100,
  search?: string,
  options?: ImportDataRequestOptions,
) {
  const params = new URLSearchParams();
  params.set("page", String(page));
  params.set("pageSize", String(pageSize));

  if (search && search.trim() !== "") {
    params.set("search", search.trim());
  }
  if (options?.cursor?.trim()) {
    params.set("cursor", options.cursor.trim());
  }
  if (Array.isArray(options?.columnFilters) && options.columnFilters.length > 0) {
    params.set("columnFilters", JSON.stringify(options.columnFilters));
  }

  const response = await apiRequest(
    "GET",
    `/api/imports/${id}/data?${params.toString()}`,
    undefined,
    options,
  );

  return parseApiJson(response, importDataPageResponseSchema, `/api/imports/${id}/data`);
}

export async function analyzeImport(id: string, options?: ImportRequestOptions) {
  const response = await apiRequest(
    "GET",
    `/api/imports/${id}/analyze`,
    undefined,
    options,
  );
  return response.json();
}

export async function analyzeAll(options?: ImportRequestOptions) {
  const response = await apiRequest(
    "GET",
    "/api/analyze/all",
    undefined,
    options,
  );
  return response.json();
}

import { getCsrfHeader } from "./api/shared";
import { apiErrorPayloadSchema } from "@shared/api-contracts";
import {
  broadcastForcedLogout,
  setBannedSessionFlag,
  setStoredForcePasswordChange,
} from "./auth-session";
import { getBrowserLocalStorage, safeSetStorageItem } from "./browser-storage";
import { createClientRandomId } from "./secure-id";

const DEFAULT_API_REQUEST_TIMEOUT_MS = 60_000;

export function createApiRequestId() {
  return createClientRandomId("api");
}

export function createApiHeaders(headers?: HeadersInit): Record<string, string> {
  const normalizedHeaders = new Headers(headers || undefined);
  const existingRequestId = String(normalizedHeaders.get("x-request-id") || "").trim();
  if (!existingRequestId) {
    normalizedHeaders.set("x-request-id", createApiRequestId());
  }

  return Object.fromEntries(normalizedHeaders.entries());
}

function looksLikeHtmlDocument(value: string) {
  return /<!doctype html|<html[\s>]|<body[\s>]|<head[\s>]/i.test(value);
}

function normalizePlainTextErrorMessage(res: Response, text: string) {
  const normalizedText = String(text || "").replace(/\s+/g, " ").trim();

  if (res.status === 413) {
    return "The selected file is too large to import. Try a smaller file or increase the server upload limit.";
  }

  if (looksLikeHtmlDocument(normalizedText)) {
    return `The server returned an unexpected ${res.status} error page.`;
  }

  if (!normalizedText) {
    return res.statusText || "Request failed";
  }

  return normalizedText.length > 240
    ? `${normalizedText.slice(0, 237)}...`
    : normalizedText;
}

type ApiErrorPayload = Record<string, unknown> & {
  error?: unknown;
  message?: unknown;
};

function isObjectRecord(value: unknown): value is Record<string, unknown> {
  return Boolean(value) && typeof value === "object" && !Array.isArray(value);
}

function parseJsonObject(text: string): ApiErrorPayload | null {
  try {
    const parsed = JSON.parse(text) as unknown;
    if (!isObjectRecord(parsed)) {
      return null;
    }

    const normalized = apiErrorPayloadSchema.safeParse(parsed);
    return normalized.success && isObjectRecord(normalized.data) ? normalized.data : parsed;
  } catch {
    return null;
  }
}

function readApiMessage(payload: ApiErrorPayload | null): string {
  const nestedMessage = isObjectRecord(payload?.error) ? payload.error.message : undefined;
  if (typeof nestedMessage === "string" && nestedMessage.trim()) {
    return nestedMessage;
  }

  const message = payload?.message;
  return typeof message === "string" ? message : "";
}

export async function throwIfResNotOk(res: Response) {
  if (!res.ok) {
    const text = (await res.text()) || res.statusText;
    const requestId = String(res.headers.get("x-request-id") || "").trim();
    const parsed = parseJsonObject(text);

    if (parsed?.banned) {
      setBannedSessionFlag(true);
    }

    if (parsed?.forcePasswordChange) {
      setStoredForcePasswordChange(true);
      if (typeof window !== "undefined") {
        window.dispatchEvent(
          new CustomEvent("force-password-change", {
            detail: parsed,
          }),
        );
      }
    }

    if (parsed?.forceLogout) {
      broadcastForcedLogout(readApiMessage(parsed));
    }

    if (res.status === 503) {
      try {
        if (parsed?.maintenance) {
          safeSetStorageItem(getBrowserLocalStorage(), "maintenanceState", JSON.stringify(parsed));
          if (typeof window !== "undefined") {
            window.location.href = "/maintenance";
          }
        }
      } catch {
        // ignore JSON parse failure, keep default error path
      }
    }

    const errorMessage = readApiMessage(parsed) || normalizePlainTextErrorMessage(res, text);
    const normalizedPayload = parsed || { message: errorMessage };
    if (requestId && !normalizedPayload.requestId) {
      normalizedPayload.requestId = requestId;
    }
    throw new Error(
      `${res.status}: ${JSON.stringify(normalizedPayload)}`,
    );
  }
}

type ApiRequestOptions = {
  headers?: Record<string, string>;
  signal?: AbortSignal | undefined;
  timeoutMs?: number | false | undefined;
};

function resolveApiRequestTimeoutMs(options?: ApiRequestOptions): number | null {
  if (options?.timeoutMs === false) {
    return null;
  }

  if (typeof options?.timeoutMs === "number" && Number.isFinite(options.timeoutMs)) {
    return Math.max(1, Math.trunc(options.timeoutMs));
  }

  // Preserve caller-owned AbortSignal identity when one is already provided.
  if (options?.signal) {
    return null;
  }

  return DEFAULT_API_REQUEST_TIMEOUT_MS;
}

function buildApiRequestTimeoutError(method: string, url: string, timeoutMs: number) {
  return new Error(`Request timed out after ${timeoutMs}ms: ${String(method || "GET").toUpperCase()} ${url}`);
}

function isNavigatorOffline() {
  return typeof navigator !== "undefined" && navigator.onLine === false;
}

function buildOfflineApiRequestError() {
  return new Error("You appear to be offline. Check your internet connection and try again.");
}

function isLikelyOfflineFetchFailure(error: unknown) {
  if (!isNavigatorOffline()) {
    return false;
  }

  if (error instanceof TypeError) {
    return true;
  }

  return error instanceof Error
    && /failed to fetch|networkerror|load failed|network request failed/i.test(error.message);
}

function createApiRequestSignal(options?: ApiRequestOptions): {
  cleanup: () => void;
  signal?: AbortSignal | undefined;
  timedOut: () => boolean;
  timeoutMs: number | null;
} {
  const timeoutMs = resolveApiRequestTimeoutMs(options);
  if (!timeoutMs) {
    return {
      cleanup: () => {},
      signal: options?.signal,
      timedOut: () => false,
      timeoutMs: null,
    };
  }

  const controller = new AbortController();
  const callerSignal = options?.signal;
  let timeoutTriggered = false;
  let timeoutHandle: ReturnType<typeof setTimeout> | null = setTimeout(() => {
    timeoutTriggered = true;
    controller.abort();
  }, timeoutMs);
  const handleCallerAbort = () => {
    controller.abort();
  };

  if (callerSignal?.aborted) {
    controller.abort();
  } else if (callerSignal) {
    callerSignal.addEventListener("abort", handleCallerAbort, { once: true });
  }

  return {
    cleanup: () => {
      if (timeoutHandle !== null) {
        clearTimeout(timeoutHandle);
        timeoutHandle = null;
      }
      callerSignal?.removeEventListener("abort", handleCallerAbort);
    },
    signal: controller.signal,
    timedOut: () => timeoutTriggered,
    timeoutMs,
  };
}

export async function apiRequest(
  method: string,
  url: string,
  data?: unknown | undefined,
  options?: ApiRequestOptions,
): Promise<Response> {
  if (isNavigatorOffline()) {
    throw buildOfflineApiRequestError();
  }

  const isFormDataPayload =
    typeof FormData !== "undefined"
    && data instanceof FormData;
  const headers = createApiHeaders({
    ...(String(method || "").toUpperCase() === "GET"
      || String(method || "").toUpperCase() === "HEAD"
      || String(method || "").toUpperCase() === "OPTIONS"
      ? {}
      : (getCsrfHeader() as Record<string, string>)),
    ...(options?.headers || {}),
  });
  if (data && !isFormDataPayload) headers["Content-Type"] = "application/json";

  const requestInit: RequestInit = {
    method,
    headers,
    credentials: "include",
  };
  if (data) {
    requestInit.body = isFormDataPayload ? data as FormData : JSON.stringify(data);
  }
  const requestSignal = createApiRequestSignal(options);
  if (requestSignal.signal) {
    requestInit.signal = requestSignal.signal;
  }

  try {
    const res = await fetch(url, requestInit);

    await throwIfResNotOk(res);
    return res;
  } catch (error) {
    if (
      requestSignal.timeoutMs
      && requestSignal.timedOut()
      && error instanceof DOMException
      && error.name === "AbortError"
    ) {
      throw buildApiRequestTimeoutError(method, url, requestSignal.timeoutMs);
    }
    if (isLikelyOfflineFetchFailure(error)) {
      throw buildOfflineApiRequestError();
    }
    throw error;
  } finally {
    requestSignal.cleanup();
  }
}

export const API_BASE = "";

export function getAuthHeader(): HeadersInit {
  return {};
}

export const CSRF_COOKIE_NAME = "sqr_csrf";

export function readCookieValue(name: string): string | null {
  if (typeof document === "undefined") {
    return null;
  }

  const target = `${name}=`;
  const segments = String(document.cookie || "").split(";");
  for (const segment of segments) {
    const value = String(segment || "").trim();
    if (!value.startsWith(target)) {
      continue;
    }
    const rawCookieValue = value.slice(target.length);
    if (!rawCookieValue) {
      return null;
    }
    try {
      return decodeURIComponent(rawCookieValue);
    } catch {
      return rawCookieValue;
    }
  }

  return null;
}

export function getCsrfToken(): string | null {
  return readCookieValue(CSRF_COOKIE_NAME);
}

export function getCsrfHeader(): HeadersInit {
  const token = getCsrfToken();
  if (!token) {
    return {};
  }
  return { "X-CSRF-Token": token };
}

import type { User } from "@/app/types";
import { createClientRandomId } from "@/lib/secure-id";
import {
  clearLegacyAuthLocalStorage,
  clearLegacyAuthLocalStorageValue,
} from "@/lib/legacy-auth-storage";

const AUTH_SESSION_HINT_COOKIE_NAME = "sqr_auth_hint";
const AUTH_NOTICE_STORAGE_KEY = "auth_notice";
const FORCE_LOGOUT_EVENT_NAME = "force-logout";
const FORCE_LOGOUT_BROADCAST_CHANNEL_NAME = "sqr-auth-force-logout";
const AUTH_SESSION_STORAGE_KEYS = [
  "activityId",
  "banned",
  "fingerprint",
  "forcePasswordChange",
  "role",
  "user",
  "username",
] as const;

type AuthSessionStorageKey = (typeof AUTH_SESSION_STORAGE_KEYS)[number];

type ForcedLogoutPayload = {
  message?: string;
  nonce?: string;
};

type ForcedLogoutListener = (payload: ForcedLogoutPayload) => void;

function canUseAuthStorage() {
  return typeof window !== "undefined"
    && typeof sessionStorage !== "undefined";
}

function readAuthSessionValue(key: AuthSessionStorageKey): string | null {
  if (!canUseAuthStorage()) {
    return null;
  }

  try {
    const sessionValue = sessionStorage.getItem(key);
    if (sessionValue !== null) {
      return sessionValue;
    }

    clearLegacyAuthLocalStorageValue(key);
  } catch {
    return null;
  }

  return null;
}

function writeAuthSessionValue(key: AuthSessionStorageKey, value: string) {
  if (!canUseAuthStorage()) {
    return;
  }

  try {
    sessionStorage.setItem(key, value);
    clearLegacyAuthLocalStorageValue(key);
  } catch {
    // Ignore storage access failures and fall back to the active in-memory session.
  }
}

function removeAuthSessionValue(key: AuthSessionStorageKey) {
  if (!canUseAuthStorage()) {
    return;
  }

  try {
    sessionStorage.removeItem(key);
    clearLegacyAuthLocalStorageValue(key);
  } catch {
    // Ignore storage access failures during best-effort cleanup.
  }
}

function clearAuthSessionHintCookie() {
  if (typeof document === "undefined") return;

  document.cookie = `${AUTH_SESSION_HINT_COOKIE_NAME}=; Max-Age=0; path=/; SameSite=Lax`;
}

function normalizeAuthNoticeMessage(message: string | null | undefined): string {
  return String(message || "").trim();
}

function parseAuthNoticePayload(raw: string | null | undefined): string {
  const normalized = String(raw || "").trim();
  if (!normalized) {
    return "";
  }

  try {
    const parsed = JSON.parse(normalized) as { message?: unknown };
    return normalizeAuthNoticeMessage(typeof parsed?.message === "string" ? parsed.message : "");
  } catch {
    return normalized;
  }
}

export function persistAuthNotice(message: string | null | undefined) {
  if (!canUseAuthStorage()) {
    return;
  }

  const normalized = normalizeAuthNoticeMessage(message);
  if (!normalized) {
    try {
      sessionStorage.removeItem(AUTH_NOTICE_STORAGE_KEY);
    } catch {
      // Ignore storage cleanup failures.
    }
    return;
  }

  try {
    sessionStorage.setItem(
      AUTH_NOTICE_STORAGE_KEY,
      JSON.stringify({
        message: normalized,
      }),
    );
  } catch {
    // Ignore storage write failures during best-effort notice persistence.
  }
}

export function consumeStoredAuthNotice(): string {
  if (!canUseAuthStorage()) {
    return "";
  }

  try {
    const raw = sessionStorage.getItem(AUTH_NOTICE_STORAGE_KEY);
    sessionStorage.removeItem(AUTH_NOTICE_STORAGE_KEY);
    return parseAuthNoticePayload(raw);
  } catch {
    return "";
  }
}

export function parseForcedLogoutStorageValue(raw: string | null | undefined): ForcedLogoutPayload | null {
  const normalized = String(raw || "").trim();
  if (!normalized) {
    return null;
  }

  if (normalized === "true") {
    return {};
  }

  try {
    const parsed = JSON.parse(normalized) as ForcedLogoutPayload;
    return {
      message: normalizeAuthNoticeMessage(parsed?.message),
    };
  } catch {
    return {};
  }
}

function normalizeForcedLogoutPayload(raw: unknown): ForcedLogoutPayload | null {
  if (typeof raw === "string" || raw === null || raw === undefined) {
    return parseForcedLogoutStorageValue(raw);
  }

  if (typeof raw !== "object") {
    return null;
  }

  const parsed = raw as {
    message?: unknown;
    nonce?: unknown;
  };

  const message = normalizeAuthNoticeMessage(
    typeof parsed.message === "string" ? parsed.message : "",
  );
  const nonce = typeof parsed.nonce === "string" ? parsed.nonce.trim() : "";

  return {
    ...(message ? { message } : {}),
    ...(nonce ? { nonce } : {}),
  };
}

function createForcedLogoutPayload(message?: string | null | undefined): ForcedLogoutPayload {
  const normalizedMessage = normalizeAuthNoticeMessage(message);
  return normalizedMessage
    ? {
      message: normalizedMessage,
      nonce: createClientRandomId("force-logout"),
    }
    : {};
}

function createForceLogoutBroadcastChannel(): BroadcastChannel | null {
  if (typeof BroadcastChannel !== "function") {
    return null;
  }

  try {
    return new BroadcastChannel(FORCE_LOGOUT_BROADCAST_CHANNEL_NAME);
  } catch {
    return null;
  }
}

export function broadcastForcedLogoutToOtherTabs(message?: string | null | undefined) {
  const payload = createForcedLogoutPayload(message);
  const channel = createForceLogoutBroadcastChannel();
  if (!channel) {
    return;
  }

  try {
    channel.postMessage(payload);
  } catch {
    // Ignore cross-tab broadcast channel failures.
  } finally {
    channel.close();
  }
}

export function broadcastForcedLogout(message?: string | null | undefined) {
  const payload = createForcedLogoutPayload(message);
  broadcastForcedLogoutToOtherTabs(payload.message);

  if (typeof window !== "undefined") {
    window.dispatchEvent(
      new CustomEvent(FORCE_LOGOUT_EVENT_NAME, {
        detail: Object.keys(payload).length > 0 ? payload : undefined,
      }),
    );
  }
}

export function subscribeForcedLogout(listener: ForcedLogoutListener) {
  const handleForcedLogoutEvent = (event: Event) => {
    const payload = normalizeForcedLogoutPayload(
      (event as CustomEvent<ForcedLogoutPayload | undefined>).detail,
    );
    if (payload) {
      listener(payload);
    }
  };

  let channel: BroadcastChannel | null = null;
  const handleChannelMessage = (event: MessageEvent<unknown>) => {
    const payload = normalizeForcedLogoutPayload(event.data);
    if (payload) {
      listener(payload);
    }
  };

  if (typeof window !== "undefined") {
    window.addEventListener(FORCE_LOGOUT_EVENT_NAME, handleForcedLogoutEvent);
  }

  channel = createForceLogoutBroadcastChannel();
  if (channel) {
    channel.addEventListener("message", handleChannelMessage);
  }

  return () => {
    if (typeof window !== "undefined") {
      window.removeEventListener(FORCE_LOGOUT_EVENT_NAME, handleForcedLogoutEvent);
    }
    if (channel) {
      channel.removeEventListener("message", handleChannelMessage);
      channel.close();
    }
  };
}

export function hasAuthSessionHintCookie() {
  if (typeof document === "undefined") return false;

  const cookiePrefix = `${AUTH_SESSION_HINT_COOKIE_NAME}=`;
  return document.cookie.split(";").some((part) => part.trim().startsWith(cookiePrefix));
}

export function getStoredAuthenticatedUser(): User | null {
  const raw = readAuthSessionValue("user");
  if (!raw) {
    return null;
  }

  try {
    const parsed = JSON.parse(raw) as User;
    if (!parsed?.username || !parsed?.role) {
      throw new Error("Invalid cached user");
    }
    return parsed;
  } catch {
    removeAuthSessionValue("user");
    removeAuthSessionValue("username");
    removeAuthSessionValue("role");
    return null;
  }
}

export function getStoredUsername(): string {
  const cachedUser = getStoredAuthenticatedUser();
  if (cachedUser?.username) {
    return String(cachedUser.username).trim();
  }

  return String(readAuthSessionValue("username") || "").trim();
}

export function getStoredRole(): string {
  const cachedUser = getStoredAuthenticatedUser();
  if (cachedUser?.role) {
    return String(cachedUser.role).trim();
  }

  return String(readAuthSessionValue("role") || "").trim();
}

export function getStoredForcePasswordChange(): boolean {
  return readAuthSessionValue("forcePasswordChange") === "1";
}

export function setStoredForcePasswordChange(required: boolean) {
  if (required) {
    writeAuthSessionValue("forcePasswordChange", "1");
    return;
  }

  removeAuthSessionValue("forcePasswordChange");
}

export function getStoredActivityId(): string {
  return String(readAuthSessionValue("activityId") || "").trim();
}

export function setStoredActivityId(activityId: string | null | undefined) {
  const normalized = String(activityId || "").trim();
  if (!normalized) {
    removeAuthSessionValue("activityId");
    return;
  }

  writeAuthSessionValue("activityId", normalized);
}

export function getStoredFingerprint(): string {
  return String(readAuthSessionValue("fingerprint") || "").trim();
}

export function setStoredFingerprint(fingerprint: string | null | undefined) {
  const normalized = String(fingerprint || "").trim();
  if (!normalized) {
    removeAuthSessionValue("fingerprint");
    return;
  }

  writeAuthSessionValue("fingerprint", normalized);
}

export function isBannedSessionFlagSet(): boolean {
  return readAuthSessionValue("banned") === "1";
}

export function setBannedSessionFlag(isBanned: boolean) {
  if (isBanned) {
    writeAuthSessionValue("banned", "1");
    return;
  }

  removeAuthSessionValue("banned");
}

export function persistAuthenticatedUser(user: User) {
  writeAuthSessionValue("username", String(user.username || "").trim());
  writeAuthSessionValue("role", String(user.role || "").trim());
  writeAuthSessionValue("user", JSON.stringify(user));
  setStoredForcePasswordChange(Boolean(user.mustChangePassword));
}

export function clearAuthenticatedUserStorage() {
  clearAuthSessionHintCookie();
  for (const key of AUTH_SESSION_STORAGE_KEYS) {
    removeAuthSessionValue(key);
  }
  clearLegacyAuthLocalStorage();
  if (typeof sessionStorage !== "undefined") {
    try {
      sessionStorage.removeItem("collection_staff_nickname");
      sessionStorage.removeItem("collection_staff_nickname_auth");
    } catch {
      // Ignore storage cleanup failures.
    }
  }
}

let fallbackCounter = 0;

function readBrowserCrypto(): Crypto | undefined {
  return typeof globalThis.crypto === "object" ? globalThis.crypto : undefined;
}

function nextFallbackToken(): string {
  fallbackCounter = (fallbackCounter + 1) % Number.MAX_SAFE_INTEGER;
  const highResolutionTime = typeof performance !== "undefined" && typeof performance.now === "function"
    ? Math.trunc(performance.now() * 1_000).toString(36)
    : "0";

  return `${Date.now().toString(36)}-${highResolutionTime}-${fallbackCounter.toString(36)}`;
}

export function createClientRandomId(prefix?: string): string {
  const crypto = readBrowserCrypto();
  const randomToken = typeof crypto?.randomUUID === "function"
    ? crypto.randomUUID()
    : createClientRandomHex(16);

  return prefix ? `${prefix}-${randomToken}` : randomToken;
}

export function createClientRandomHex(byteLength = 16): string {
  const crypto = readBrowserCrypto();
  const normalizedByteLength = Math.max(1, Math.trunc(byteLength));

  if (typeof crypto?.getRandomValues === "function") {
    const bytes = new Uint8Array(normalizedByteLength);
    crypto.getRandomValues(bytes);
    return Array.from(bytes, (byte) => byte.toString(16).padStart(2, "0")).join("");
  }

  return nextFallbackToken();
}

export function createClientRandomUnitInterval(): number {
  const crypto = readBrowserCrypto();

  if (typeof crypto?.getRandomValues === "function") {
    const bytes = new Uint32Array(1);
    crypto.getRandomValues(bytes);
    return bytes[0] / 0x1_0000_0000;
  }

  fallbackCounter = (fallbackCounter + 1) % Number.MAX_SAFE_INTEGER;
  return ((Date.now() + fallbackCounter) % 1_000_000) / 1_000_000;
}

