export type BrowserStorageLike = Pick<Storage, "getItem" | "setItem" | "removeItem" | "key"> & {
  length: number;
};

export function getBrowserLocalStorage(): Storage | null {
  return typeof localStorage !== "undefined" ? localStorage : null;
}

export function getBrowserSessionStorage(): Storage | null {
  return typeof sessionStorage !== "undefined" ? sessionStorage : null;
}

export function isQuotaExceededStorageError(error: unknown): boolean {
  if (!(error instanceof Error)) {
    return false;
  }

  return error.name === "QuotaExceededError" || error.name === "NS_ERROR_DOM_QUOTA_REACHED";
}

export function safeGetStorageItem(
  storage: Pick<Storage, "getItem"> | null | undefined,
  key: string,
): string | null {
  if (!storage) {
    return null;
  }

  try {
    return storage.getItem(key);
  } catch {
    return null;
  }
}

export function safeRemoveStorageItem(
  storage: Pick<Storage, "removeItem"> | null | undefined,
  key: string,
): void {
  if (!storage) {
    return;
  }

  try {
    storage.removeItem(key);
  } catch {
    // Ignore best-effort storage cleanup failures.
  }
}

export function safeSetStorageItem(
  storage: Pick<Storage, "setItem"> | null | undefined,
  key: string,
  value: string,
  options?: {
    onQuotaExceeded?: () => void;
  },
): boolean {
  if (!storage) {
    return false;
  }

  try {
    storage.setItem(key, value);
    return true;
  } catch (error) {
    if (!isQuotaExceededStorageError(error)) {
      return false;
    }

    try {
      options?.onQuotaExceeded?.();
      storage.setItem(key, value);
      return true;
    } catch {
      return false;
    }
  }
}

import { z } from "zod";

export async function parseApiJson<TSchema extends z.ZodTypeAny>(
  response: Response,
  schema: TSchema,
  endpoint: string,
): Promise<z.infer<TSchema>> {
  const payload = await response.json();
  const parsed = schema.safeParse(payload);

  if (parsed.success) {
    return parsed.data;
  }

  throw new Error(`API contract mismatch for ${endpoint}`);
}

import { apiRequest } from "../api-client";
import { auditLogsResponseSchema } from "@shared/api-contracts";
import { parseApiJson } from "./contract";

export async function getAuditLogs(params?: {
  page?: number | undefined;
  pageSize?: number | undefined;
  action?: string | undefined;
  performedBy?: string | undefined;
  targetUser?: string | undefined;
  search?: string | undefined;
  dateFrom?: string | undefined;
  dateTo?: string | undefined;
  sortBy?: string | undefined;
}) {
  const query = new URLSearchParams();
  if (params?.page) query.set("page", String(params.page));
  if (params?.pageSize) query.set("pageSize", String(params.pageSize));
  if (params?.action) query.set("action", params.action);
  if (params?.performedBy) query.set("performedBy", params.performedBy);
  if (params?.targetUser) query.set("targetUser", params.targetUser);
  if (params?.search) query.set("search", params.search);
  if (params?.dateFrom) query.set("dateFrom", params.dateFrom);
  if (params?.dateTo) query.set("dateTo", params.dateTo);
  if (params?.sortBy) query.set("sortBy", params.sortBy);
  const suffix = query.size > 0 ? `?${query.toString()}` : "";
  const response = await apiRequest("GET", `/api/audit-logs${suffix}`);
  return parseApiJson(response, auditLogsResponseSchema, "/api/audit-logs");
}

